SELECT rank
FROM leaderboard
WHERE contestant_id = 1;

SELECT name
FROM contestants
WHERE competition_type = 'Baking';

SELECT COUNT(*) AS total_entries
FROM contestants
WHERE competition_type = 'Baking';

SELECT AVG(score) AS average_score
FROM judges_scores
WHERE judge_id = 0 AND round_number = 0;

SELECT name
FROM contestants
WHERE contestant_id = 1;

SELECT rank
FROM leaderboard
ORDER BY rank;

SELECT MIN(score) 
FROM judges_scores 
WHERE round_number = 0;

SELECT contestant_id, total_score
FROM leaderboard
ORDER BY total_score DESC;

SELECT rank
FROM leaderboard
ORDER BY rank ASC;

SELECT contestant_id, rank, total_score
FROM leaderboard
ORDER BY rank ASC;

SELECT rank 
FROM leaderboard 
ORDER BY rank ASC;

SELECT name, entry_number
FROM contestants
ORDER BY entry_number;
